#!/usr/bin/env node
/**
 * inject-build-hash.js
 *
 * Reads the webpack content hash from build/index.asset.php (generated by
 * @wordpress/scripts), then rewrites the ALDUS_BUILD_HASH constant in
 * aldus.php so the PHP assembly cache is automatically busted whenever the
 * JS bundle changes — even if the plugin version number hasn't been bumped.
 *
 * Usage (called automatically by `npm run build`):
 *   node bin/inject-build-hash.js
 */

'use strict';

const fs = require( 'fs' );
const path = require( 'path' );

const ROOT = path.resolve( __dirname, '..' );
const ASSET_FILE = path.join( ROOT, 'build', 'index.asset.php' );
const PLUGIN_FILE = path.join( ROOT, 'aldus.php' );

// ── 1. Read the asset file generated by @wordpress/scripts ─────────────────

if ( ! fs.existsSync( ASSET_FILE ) ) {
	console.warn(
		'[inject-build-hash] build/index.asset.php not found — skipping hash injection.'
	);
	process.exit( 0 );
}

const assetContent = fs.readFileSync( ASSET_FILE, 'utf8' );

// The asset file looks like:
//   <?php return array('dependencies' => [...], 'version' => 'abc123def456');
const versionMatch = assetContent.match( /'version'\s*=>\s*'([^']+)'/ );
if ( ! versionMatch ) {
	console.warn(
		'[inject-build-hash] Could not parse version from index.asset.php — skipping.'
	);
	process.exit( 0 );
}

const hash = versionMatch[ 1 ].trim();

// ── 2. Rewrite the constant in aldus.php ────────────────────────────────────

const pluginContent = fs.readFileSync( PLUGIN_FILE, 'utf8' );

const patternDefinedOr =
	/defined\(\s*'ALDUS_BUILD_HASH'\s*\)\s*\|\|\s*define\(\s*'ALDUS_BUILD_HASH'\s*,\s*'[^']*'\s*\)\s*;/;
const patternDefineOnly =
	/define\(\s*'ALDUS_BUILD_HASH'\s*,\s*'[^']*'\s*\)/;

let updated = pluginContent.replace(
	patternDefinedOr,
	`defined( 'ALDUS_BUILD_HASH' ) || define( 'ALDUS_BUILD_HASH', '${ hash }' );`
);

if ( updated === pluginContent ) {
	updated = pluginContent.replace(
		patternDefineOnly,
		`define( 'ALDUS_BUILD_HASH', '${ hash }' )`
	);
}

if (
	! patternDefinedOr.test( pluginContent ) &&
	! patternDefineOnly.test( pluginContent )
) {
	console.warn(
		'[inject-build-hash] ALDUS_BUILD_HASH constant not found in aldus.php — skipping.'
	);
	process.exit( 0 );
}

fs.writeFileSync( PLUGIN_FILE, updated, 'utf8' );
console.log(
	`[inject-build-hash] Wrote ALDUS_BUILD_HASH = '${ hash }' to aldus.php`
);
